import{_ as i,y as s,a as l,o as d,g as t,D as a,a2 as r,I as o}from"./chunks/framework.DCcmcJcL.js";const y=JSON.parse('{"title":"B2B Suite Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"b2b-ecommerce-platform/configuration.md","filePath":"b2b-ecommerce-platform/configuration.md","lastUpdated":1782735915000}'),m={name:"b2b-ecommerce-platform/configuration.md"};function u(p,e,g,c,h,f){const n=s("ImagePopup");return d(),l("div",null,[e[0]||(e[0]=t("h1",{id:"b2b-suite-configuration",tabindex:"-1"},[o("B2B Suite Configuration "),t("a",{class:"header-anchor",href:"#b2b-suite-configuration","aria-label":'Permalink to "B2B Suite Configuration"'},"​")],-1)),e[1]||(e[1]=t("p",null,"Before companies can use any B2B feature, the B2B Suite must be enabled and configured from the admin panel. All B2B settings are grouped together so you can control company onboarding, quotations, company credit and email notifications from a single place.",-1)),e[2]||(e[2]=t("p",null,[o("Navigate to "),t("strong",null,"Admin Panel → Configure → B2B Suite"),o(".")],-1)),a(n,{src:"/images/b2b-ecommerce-platform/1-configuration.png",alt:"B2B Suite Configuration"}),e[3]||(e[3]=r('<h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><p>The <strong>General</strong> section controls the core behavior of the suite.</p><p><strong>1) Enable B2B Suite –</strong> Master switch for the entire suite. When disabled, all B2B routes, menus, the company registration option and every company-specific feature are hidden from the storefront and admin.</p><p><strong>2) Require Company Approval –</strong> When enabled, newly registered companies remain in a <strong>Pending</strong> state and cannot sign in until an administrator approves (activates) them. When disabled, companies can sign in immediately after registering.</p><p><strong>3) Number Of Requisition Lists –</strong> The maximum number of requisition lists each company is allowed to create.</p>',5)),a(n,{src:"/images/b2b-ecommerce-platform/2-configuration.png",alt:"B2B General Settings"}),e[4]||(e[4]=r('<h2 id="quotations-purchase-orders" tabindex="-1">Quotations &amp; Purchase Orders <a class="header-anchor" href="#quotations-purchase-orders" aria-label="Permalink to &quot;Quotations &amp; Purchase Orders&quot;">​</a></h2><p>This section configures how quotations and purchase orders are numbered, when they expire, and what attachments buyers can upload.</p><p><strong>1) Quotation Prefix –</strong> Prefix used when generating quotation numbers (default <code>QO</code>).</p><p><strong>2) Purchase Order Prefix –</strong> Prefix used when generating purchase order numbers (default <code>PO</code>).</p><p><strong>3) Default Padding –</strong> Zero-padding applied to the auto-incrementing quotation / purchase order number.</p><p><strong>4) Default Expiration Period –</strong> How long a quotation stays valid.</p><p><strong>5) Expiration Period Unit –</strong> The unit for the expiration period — <strong>Days</strong>, <strong>Weeks</strong> or <strong>Months</strong>.</p><p><strong>6) Minimum Cart Amount –</strong> The minimum cart total required before a customer can request a quote. Set to <code>0</code> to allow any amount.</p><p><strong>7) Minimum Amount Message –</strong> The message shown to the customer when the cart total is below the minimum required amount.</p><p><strong>8) Supported File Formats –</strong> Comma-separated list of file extensions buyers may attach to a quotation (e.g. <code>doc, docx, xls, xlsx, pdf, txt, jpg, png, jpeg</code>).</p><p><strong>9) Maximum File Size (MB) –</strong> The maximum size allowed for an uploaded attachment.</p>',11)),a(n,{src:"/images/b2b-ecommerce-platform/3-configuration.png",alt:"Quotations and Purchase Orders Settings"}),e[5]||(e[5]=t("h2",{id:"company-credit",tabindex:"-1"},[o("Company Credit "),t("a",{class:"header-anchor",href:"#company-credit","aria-label":'Permalink to "Company Credit"'},"​")],-1)),e[6]||(e[6]=t("p",null,[t("strong",null,"Enable Company Credit –"),o(" When enabled, companies that have an assigned credit limit can pay using the "),t("strong",null,"Pay By Credit"),o(" method at checkout. See the "),t("a",{href:"./company-credit.html"},"Company Credit"),o(" guide for the full workflow.")],-1)),a(n,{src:"/images/b2b-ecommerce-platform/4-configuration.png",alt:"Company Credit Settings"}),e[7]||(e[7]=r('<h2 id="b2b-email-notifications" tabindex="-1">B2B Email Notifications <a class="header-anchor" href="#b2b-email-notifications" aria-label="Permalink to &quot;B2B Email Notifications&quot;">​</a></h2><p>The suite sends transactional emails throughout the B2B lifecycle. Each notification has its own toggle, and all are enabled by default. Buyer emails are sent to the company, while seller emails go to the company&#39;s assigned sales representative (or the store email if none is assigned).</p><p><strong>Available notifications include:</strong></p><ul><li><strong>Company Registered</strong> – Notifies the sales team when a new company registers and is awaiting approval.</li><li><strong>Company Approved</strong> – Notifies the buyer when their company account is approved.</li><li><strong>Company Disabled</strong> – Notifies the buyer when their company account is disabled.</li><li><strong>New Sub-User Welcome</strong> – Welcomes a newly created company sub-user.</li><li><strong>Sub-User Removed</strong> – Notifies a sub-user when they are removed from the company.</li><li><strong>Credit Limit Updated</strong> – Notifies the buyer when their company credit limit changes.</li><li><strong>Credit Payment Recorded</strong> – Notifies the buyer when a payment is recorded against their balance.</li><li><strong>Quote Requested</strong> – Notifies the assigned sales rep when a buyer submits a quotation request.</li><li><strong>Quotation Sent or Revised</strong> – Notifies the buyer when the seller sends or revises a quotation.</li><li><strong>Quote Counter-Offer</strong> – Notifies the sales rep when the buyer responds with a counter-offer.</li><li><strong>New Negotiation Message</strong> – Notifies the other party when a new message is posted in the negotiation thread.</li><li><strong>Quote Accepted / Quote Rejected</strong> – Notifies the other party when a quotation is accepted or rejected.</li><li><strong>Quote Converted to Order</strong> – Notifies the buyer when their quotation becomes an order.</li><li><strong>Purchase Order Placed</strong> – Notifies the sales rep when a purchase order is placed.</li></ul>',4)),a(n,{src:"/images/b2b-ecommerce-platform/5-configuration.png",alt:"B2B Email Notification Settings"}),e[8]||(e[8]=r('<h2 id="pay-by-credit-payment-method" tabindex="-1">Pay By Credit Payment Method <a class="header-anchor" href="#pay-by-credit-payment-method" aria-label="Permalink to &quot;Pay By Credit Payment Method&quot;">​</a></h2><p>The <strong>Pay By Credit</strong> payment method is configured under <strong>Admin Panel → Configure → Sales → Payment Methods → Pay By Credit</strong>. It is shown at checkout only to companies that have an active credit account.</p><p><strong>1) Status –</strong> Enable or disable the payment method.</p><p><strong>2) Title –</strong> The label shown to the customer at checkout (default <em>Pay By Credit</em>).</p><p><strong>3) Description –</strong> A short description shown beneath the title.</p><p><strong>4) Sort Order –</strong> The position of the method in the checkout payment list.</p>',6)),a(n,{src:"/images/b2b-ecommerce-platform/6-configuration.png",alt:"Pay By Credit Payment Method"})])}const P=i(m,[["render",u]]);export{y as __pageData,P as default};
